package com.xoxo.pos.reports;
import com.xoxo.pos.accounts.*;import com.xoxo.pos.expenses.ExpenseRepository;import com.xoxo.pos.products.ProductRepository;import org.springframework.web.bind.annotation.*;import java.math.*;import java.time.LocalDate;import java.util.*;import java.util.stream.Collectors;
@RestController @RequestMapping("/api/reports") public class ReportController{private final AccountRepository accounts;private final ExpenseRepository expenses;private final ProductRepository products;public ReportController(AccountRepository accounts,ExpenseRepository expenses,ProductRepository products){this.accounts=accounts;this.expenses=expenses;this.products=products;}
@GetMapping("/daily") public DailyReport daily(@RequestParam(required=false) String date){var day=date==null||date.isBlank()?LocalDate.now():LocalDate.parse(date);var start=day.atStartOfDay();var end=start.plusDays(1);var acc=accounts.findByOpenedAtBetweenOrderByOpenedAtDesc(start,end);var exp=expenses.findByCreatedAtBetweenOrderByCreatedAtDesc(start,end);var low=products.findAll().stream().filter(p->p.isActive()&&p.getStock()!=null&&p.getLowStockAlert()!=null&&p.getStock()<=p.getLowStockAlert()).toList();var paid=acc.stream().filter(a->a.getStatus()==AccountStatus.PAID).toList();var salesTotal=paid.stream().map(Account::getTotal).reduce(BigDecimal.ZERO,BigDecimal::add);var costTotal=paid.stream().map(Account::getTotalCost).reduce(BigDecimal.ZERO,BigDecimal::add);var grossProfit=salesTotal.subtract(costTotal);var expensesTotal=exp.stream().map(e->e.getAmount()).reduce(BigDecimal.ZERO,BigDecimal::add);var estimatedNet=grossProfit.subtract(expensesTotal);var margin=salesTotal.compareTo(BigDecimal.ZERO)==0?BigDecimal.ZERO:grossProfit.multiply(BigDecimal.valueOf(100)).divide(salesTotal,2,RoundingMode.HALF_UP);var byPayment=paid.stream().collect(Collectors.groupingBy(a->a.getPaymentMethod()==null?"SIN_METODO":a.getPaymentMethod().name(),Collectors.reducing(BigDecimal.ZERO,Account::getTotal,BigDecimal::add)));Map<Long,M> map=new LinkedHashMap<>();for(var a:paid){for(var i:a.getItems()){var p=i.getProduct();map.computeIfAbsent(p.getId(),id->new M(p.getId(),p.getName(),p.getCategory())).add(i.getQuantity(),i.getSubtotal(),i.getCostSubtotal(),i.getGrossProfit());}}var productSales=map.values().stream().map(m->new ProductSaleReport(m.id,m.name,m.cat,m.qty,m.sales,m.cost,m.profit)).sorted((a,b)->b.grossProfit().compareTo(a.grossProfit())).toList();return new DailyReport(day.toString(),acc.stream().filter(a->a.getStatus()==AccountStatus.OPEN).count(),acc.stream().filter(a->a.getStatus()==AccountStatus.PAID).count(),acc.stream().filter(a->a.getStatus()==AccountStatus.CANCELLED).count(),salesTotal,costTotal,grossProfit,expensesTotal,estimatedNet,margin,byPayment,productSales,acc,exp,low);}
static class M{Long id;String name;String cat;long qty;BigDecimal sales=BigDecimal.ZERO,cost=BigDecimal.ZERO,profit=BigDecimal.ZERO;M(Long id,String name,String cat){this.id=id;this.name=name;this.cat=cat;}void add(Integer q,BigDecimal s,BigDecimal c,BigDecimal p){qty+=q;sales=sales.add(s);cost=cost.add(c);profit=profit.add(p);}}}
